import React from 'react';
//vector images
import vector1 from '../../static/vectors/thumbnails/ickis.svg';
import vector2 from '../../static/vectors/thumbnails/amnesiapsyduck.svg';
import vector3 from '../../static/vectors/thumbnails/bigpoeghost.svg';
import vector4 from '../../static/vectors/thumbnails/carrot.svg';

export default class Vector extends React.Component{

 render(){
     return (
         <div >
             <figure className="gallery">
                 <ul>
                     <li className="image-gallery-link vector"> <img src={vector1} alt="vector illustration"/></li>
                     <li className="image-gallery-link vector"><img src={vector2} alt="vector illustration"/></li>
                     <li className="image-gallery-link vector"><img src={vector3} alt="vector illustration"/></li>
                     <li className="image-gallery-link vector"><img src={vector4} alt="vector illustration"/></li>
                 </ul>
                <figcaption className="digitizer">Vector Illustration</figcaption>
             </figure>
         </div>
        )  
    }
}
